{
  "name": "@node/recipe-manager",
  "version": "1.0.0",
  "description": "Save, search, and browse recipes with ingredients, steps, tags, and timing",
  "modnet": {
    "contentType": "produce",
    "structure": "collection",
    "mechanics": ["sort", "filter"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

import { type Recipe, type RecipeInput, type RecipeFilter } from './types'

const DATA_PATH = new URL('./data/recipes.jsonl', import.meta.url).pathname

const generateId = (): string => crypto.randomUUID()

const readAll = async (): Promise<Recipe[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Recipe)
}

const writeAll = async (recipes: Recipe[]): Promise<void> => {
  const content = recipes.map((r) => JSON.stringify(r)).join('\n') + '\n'
  await Bun.write(DATA_PATH, content)
}

export const createRecipe = async (input: RecipeInput): Promise<Recipe> => {
  const now = new Date().toISOString()
  const recipe: Recipe = {
    ...input,
    id: generateId(),
    createdAt: now,
    updatedAt: now,
  }
  const recipes = await readAll()
  recipes.push(recipe)
  await writeAll(recipes)
  return recipe
}

export const getRecipe = async (id: string): Promise<Recipe | undefined> => {
  const recipes = await readAll()
  return recipes.find((r) => r.id === id)
}

export const updateRecipe = async (id: string, input: RecipeInput): Promise<Recipe | undefined> => {
  const recipes = await readAll()
  const index = recipes.findIndex((r) => r.id === id)
  if (index === -1) return undefined
  const updated: Recipe = {
    ...input,
    id,
    createdAt: recipes[index].createdAt,
    updatedAt: new Date().toISOString(),
  }
  recipes[index] = updated
  await writeAll(recipes)
  return updated
}

export const deleteRecipe = async (id: string): Promise<boolean> => {
  const recipes = await readAll()
  const filtered = recipes.filter((r) => r.id !== id)
  if (filtered.length === recipes.length) return false
  await writeAll(filtered)
  return true
}

export const listRecipes = async (filter?: RecipeFilter): Promise<Recipe[]> => {
  let recipes = await readAll()

  if (filter?.query) {
    const q = filter.query.toLowerCase()
    recipes = recipes.filter(
      (r) =>
        r.title.toLowerCase().includes(q) ||
        r.ingredients.some((i) => i.name.toLowerCase().includes(q))
    )
  }

  if (filter?.tags && filter.tags.length > 0) {
    recipes = recipes.filter((r) => filter.tags!.every((tag) => r.tags.includes(tag)))
  }

  return recipes.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt))
}

import { type DietaryTag, type RecipeInput } from './types'
import { createRecipe, getRecipe, updateRecipe, deleteRecipe, listRecipes } from './store'
import { renderRecipeList, renderRecipeDetail, renderRecipeForm } from './views'

const parseJsonBody = async (req: Request): Promise<unknown> => {
  const text = await req.text()
  return JSON.parse(text)
}

export const serve = () =>
  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)
      const { pathname } = url
      const method = req.method

      // API routes
      if (pathname.startsWith('/api/recipes')) {
        if (pathname === '/api/recipes' && method === 'GET') {
          const query = url.searchParams.get('q') ?? undefined
          const tagsParam = url.searchParams.get('tags')
          const tags = tagsParam ? (tagsParam.split(',') as DietaryTag[]) : undefined
          const recipes = await listRecipes({ query, tags })
          return Response.json(recipes)
        }

        if (pathname === '/api/recipes' && method === 'POST') {
          const body = (await parseJsonBody(req)) as RecipeInput
          const recipe = await createRecipe(body)
          return Response.json(recipe, { status: 201 })
        }

        const idMatch = pathname.match(/^\/api\/recipes\/([^/]+)$/)
        if (idMatch) {
          const id = idMatch[1]

          if (method === 'GET') {
            const recipe = await getRecipe(id)
            if (!recipe) return Response.json({ error: 'Not found' }, { status: 404 })
            return Response.json(recipe)
          }

          if (method === 'PUT') {
            const body = (await parseJsonBody(req)) as RecipeInput
            const recipe = await updateRecipe(id, body)
            if (!recipe) return Response.json({ error: 'Not found' }, { status: 404 })
            return Response.json(recipe)
          }

          if (method === 'DELETE') {
            const deleted = await deleteRecipe(id)
            if (!deleted) return Response.json({ error: 'Not found' }, { status: 404 })
            return Response.json({ ok: true })
          }
        }
      }

      // HTML view routes
      if (pathname === '/' || pathname === '/recipes') {
        const query = url.searchParams.get('q') ?? ''
        const tagsParam = url.searchParams.get('tags')
        const tags = tagsParam ? (tagsParam.split(',') as DietaryTag[]) : []
        const recipes = await listRecipes({ query, tags: tags.length > 0 ? tags : undefined })
        const html = renderRecipeList(recipes, tags, query)
        return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
      }

      if (pathname === '/recipes/new') {
        const html = renderRecipeForm()
        return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
      }

      const detailMatch = pathname.match(/^\/recipes\/([^/]+)$/)
      if (detailMatch) {
        const recipe = await getRecipe(detailMatch[1])
        if (!recipe) return new Response('Recipe not found', { status: 404 })
        const html = renderRecipeDetail(recipe)
        return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
      }

      const editMatch = pathname.match(/^\/recipes\/([^/]+)\/edit$/)
      if (editMatch) {
        const recipe = await getRecipe(editMatch[1])
        if (!recipe) return new Response('Recipe not found', { status: 404 })
        const html = renderRecipeForm(recipe)
        return new Response(html, { headers: { 'content-type': 'text/html; charset=utf-8' } })
      }

      return new Response('Not found', { status: 404 })
    },
  })

serve()
